import { app } from 'electron';
import fs from 'fs';
import path from 'path';

interface UpdatePreferencesData {
  skippedVersion?: string | null;
}

const DEFAULT_PREFERENCES: UpdatePreferencesData = {
  skippedVersion: null,
};

export class UpdatePreferences {
  private cache: UpdatePreferencesData | null = null;

  private get filePath(): string {
    const dir = app.getPath('userData');
    return path.join(dir, 'update-preferences.json');
  }

  private load(): UpdatePreferencesData {
    if (this.cache) {
      return this.cache;
    }

    try {
      const raw = fs.readFileSync(this.filePath, 'utf-8');
      const parsed = JSON.parse(raw) as UpdatePreferencesData;
      this.cache = {
        skippedVersion: parsed.skippedVersion ?? null,
      };
    } catch {
      this.cache = { ...DEFAULT_PREFERENCES };
    }

    return this.cache!;
  }

  private persist(data: UpdatePreferencesData) {
    this.cache = data;
    try {
      fs.writeFileSync(this.filePath, JSON.stringify(data, null, 2), 'utf-8');
    } catch {
      // Ignore write errors; failing to persist preferences is non-fatal.
    }
  }

  getSkippedVersion(): string | null {
    const data = this.load();
    return data.skippedVersion ?? null;
  }

  setSkippedVersion(version: string) {
    const data = this.load();
    if (data.skippedVersion === version) {
      return;
    }
    this.persist({
      ...data,
      skippedVersion: version,
    });
  }

  clearSkippedVersion() {
    const data = this.load();
    if (!data.skippedVersion) {
      return;
    }
    this.persist({
      ...data,
      skippedVersion: null,
    });
  }
}

export const updatePreferences = new UpdatePreferences();

